INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2387, 218880, 10, 47, '关于魔力的一些点滴', '很多人都不喜欢我写安娜苏一类的文章,呵呵,其实我如今的生活状况和生活态度写得出的也就只有那样的东西了.日子一点也不敏感了,混沌的,就这么过啊,知道吃饭睡觉和接吻,没有别的什么了.
<br>但是我还是要写写魔力的,我现在在等人过来吃饭,不知道什么时候下,但是我会把我的魔力一点一点写完的.
<br>
<br>昨天,我的帐号全部回来了,4个号,很多宝宝就不多说,70W还有.主要的是我的亚亚,我对露比形象的人不知为何有很深的喜爱,觉得设计出来的几乎每一个东西都是我的心水.哭,坐,开心,点头,看着就觉得好喜欢好喜欢,被停的时候很是郁闷了一阵,由此新开的人就全部都是黄色露比,我才不管玩的人有多少,我喜欢就是最好.而且,谁知道我为这个亚亚付出多少呀,谁知道呀,那些一个人去网吧的夜晚,那些坐在电脑面前昏昏欲睡却一点一点练级拿经验的凌晨,那些郁闷的技能(虽然技能我烧的那部分不到1/3).', '很多人都不喜欢我写安娜苏一类的文章,呵呵,其实我如今的生活状况和生活态度写得出的也就只有那样的东西了.日子一点也不敏感了,混沌的,就这么过啊,知道吃饭睡觉和接吻,没有别的什么了.

但是我还是要写写魔力的,我现在在等人过来吃饭,不知道什么时候下,但是我会把我的魔力一点一点写完的.

昨天,我的帐号全部回来了,4个号,很多宝宝就不多说,70W还有.主要的是我的亚亚,我对露比形象的人不知为何有很深的喜爱,觉得设计出来的几乎每一个东西都是我的心水.哭,坐,开心,点头,看着就觉得好喜欢好喜欢,被停的时候很是郁闷了一阵,由此新开的人就全部都是黄色露比,我才不管玩的人有多少,我喜欢就是最好.而且,谁知道我为这个亚亚付出多少呀,谁知道呀,那些一个人去网吧的夜晚,那些坐在电脑面前昏昏欲睡却一点一点练级拿经验的凌晨,那些郁闷的技能(虽然技能我烧的那部分不到1/3).', NULL, '2003-11-17 21:12:00', 13, '20031222062944_bbsid_218880_board_10_3b42d42435.html', '20031222062944');
